x=\"340\" cy=\"350\" rx=\"140\" ry=\"110\" fill=\"url(#g3)\"/>\\n    <ellipse cx=\"150\" cy=\"370\" rx=\"110\" ry=\"100\" fill=\"url(#g4)\"/>\\n  </g>\\n  <g filter=\"url(#glow)\" opacity=\"0.95\">\\n    <path d=\"M40 420 C140 320, 220 300, 300 220\" stroke=\"#ff2d7a\" stroke-width=\"18\" stroke-linecap=\"round\" fill=\"none\" stroke-linejoin=\"round\" opacity=\"0.9\"/>\\n    <path d=\"M60 380 C160 280, 240 260, 340 180\" stroke=\"#00f0ff\" stroke-width=\"14\" stroke-linecap=\"round\" fill=\"none\" opacity=\"0.9\"/>\\n    <path d=\"M120 460 C200 360, 280 340, 420 260\" stroke=\"#ffd400\" stroke-width=\"16\" stroke-linecap=\"round\" fill=\"none\" opacity=\"0.9\"/>\\n    <path d=\"M30 300 C120 220, 200 200, 320 140\" stroke=\"#66ff66\" stroke-width=\"12\" stroke-linecap=\"round\" fill=\"none\" opacity=\"0.85\"/>\\n  </g>\\n  <g transform=\"translate(256,256)\">\\n    <g>\\n      <circle r=\"60\" fill=\"white\" opacity=\"0.08\"/>\\n      <circle r=\"40\" fill=\"#ffffff\" opacity=\"0.06\"/>\\n    </g>\\n    <g>\\n      <g fill-opacity=\"0.95\">\\n        <path d=\"M0 -120 L12 -28 L-12 -28 Z\" fill=\"#ff3b81\" transform=\"rotate(0)\"/>\\n        <path d=\"M0 -120 L12 -28 L-12 -28 Z\" fill=\"#00f0ff\" transform=\"rotate(30)\"/>\\n        <path d=\"M0 -120 L12 -28 L-12 -28 Z\" fill=\"#ffd400\" transform=\"rotate(60)\"/>\\n        <path d=\"M0 -120 L12 -28 L-12 -28 Z\" fill=\"#66ff66\" transform=\"rotate(90)\"/>\\n        <path d=\"M0 -120 L12 -28 L-12 -28 Z\" fill=\"#ff7a00\" transform=\"rotate(120)\"/>\\n        <path d=\"M0 -120 L12 -28 L-12 -28 Z\" fill=\"#8a2be2\" transform=\"rotate(150)\"/>\\n        <path d=\"M0 -120 L12 -28 L-12 -28 Z\" fill=\"#ff3b81\" transform=\"rotate(180)\"/>\\n        <path d=\"M0 -120 L12 -28 L-12 -28 Z\" fill=\"#00f0ff\" transform=\"rotate(210)\"/>\\n        <path d=\"M0 -120 L12 -28 L-12 -28 Z\" fill=\"#ffd400\" transform=\"rotate(240)\"/>\\n        <path d=\"M0 -120 L12 -28 L-12 -28 Z\" fill=\"#66ff66\" transform=\"rotate(270)\"/>\\n      